import json
import os
from typing import Any, Callable
from openai import OpenAI
import anthropic

openai_client = OpenAI(api_key=os.environ['OPENAI_API_KEY'])
anthropic_client = anthropic.Anthropic(api_key=os.environ['ANTHROPIC_API_KEY'])

# ── Tool implementations ──────────────────────────────────────────────────────

def get_weather(city: str, unit: str = 'celsius') -> dict:
    """Simulated weather API."""
    data = {
        'London': {'temp_c': 15, 'condition': 'cloudy'},
        'Tokyo':  {'temp_c': 28, 'condition': 'sunny'},
        'NYC':    {'temp_c': 22, 'condition': 'partly cloudy'},
    }
    info = data.get(city, {'temp_c': 20, 'condition': 'unknown'})
    temp = info['temp_c'] if unit == 'celsius' else info['temp_c'] * 9/5 + 32
    symbol = '°C' if unit == 'celsius' else '°F'
    return {'city': city, 'temperature': f'{temp}{symbol}', 'condition': info['condition']}

def search_database(query: str, table: str = 'products') -> list[dict]:
    """Simulated DB query."""
    db = {
        'products': [
            {'id': 1, 'name': 'Widget Pro', 'price': 29.99, 'stock': 150},
            {'id': 2, 'name': 'Gadget Plus', 'price': 49.99, 'stock': 0},
            {'id': 3, 'name': 'Tool Deluxe', 'price': 99.99, 'stock': 42},
        ]
    }
    rows = db.get(table, [])
    q = query.lower()
    return [r for r in rows if q in r.get('name', '').lower()] or rows[:3]

def calculate(expression: str) -> dict:
    """Safe expression evaluator."""
    allowed = set('0123456789+-*/.(). ')
    if not all(c in allowed for c in expression):
        return {'error': 'Invalid characters'}
    try:
        result = eval(expression, {'__builtins__': {}})  # noqa: S307 — safe subset only
        return {'expression': expression, 'result': result}
    except Exception as e:
        return {'error': str(e)}

# Registry maps name → callable
TOOL_REGISTRY: dict[str, Callable] = {
    'get_weather': get_weather,
    'search_database': search_database,
    'calculate': calculate,
}

def dispatch_tool(name: str, arguments: dict) -> str:
    fn = TOOL_REGISTRY.get(name)
    if fn is None:
        return json.dumps({'error': f'Unknown tool: {name}'})
    return json.dumps(fn(**arguments))


# ── OpenAI function calling ───────────────────────────────────────────────────

OPENAI_TOOLS = [
    {
        'type': 'function',
        'function': {
            'name': 'get_weather',
            'description': 'Get current weather for a city',
            'parameters': {
                'type': 'object',
                'properties': {
                    'city': {'type': 'string', 'description': 'City name, e.g. London'},
                    'unit': {'type': 'string', 'enum': ['celsius', 'fahrenheit'], 'default': 'celsius'},
                },
                'required': ['city'],
            },
        },
    },
    {
        'type': 'function',
        'function': {
            'name': 'search_database',
            'description': 'Search the product database',
            'parameters': {
                'type': 'object',
                'properties': {
                    'query': {'type': 'string', 'description': 'Search term'},
                    'table': {'type': 'string', 'enum': ['products', 'orders'], 'default': 'products'},
                },
                'required': ['query'],
            },
        },
    },
    {
        'type': 'function',
        'function': {
            'name': 'calculate',
            'description': 'Evaluate a mathematical expression',
            'parameters': {
                'type': 'object',
                'properties': {
                    'expression': {'type': 'string', 'description': 'Math expression, e.g. 2 + 2 * 3'},
                },
                'required': ['expression'],
            },
        },
    },
]


def openai_tool_loop(user_message: str, max_rounds: int = 5) -> str:
    """Full agentic loop: call tools until the model produces a text response."""
    messages = [{'role': 'user', 'content': user_message}]

    for _round in range(max_rounds):
        response = openai_client.chat.completions.create(
            model='gpt-4o-mini',
            messages=messages,
            tools=OPENAI_TOOLS,
            tool_choice='auto',
        )
        msg = response.choices[0].message
        messages.append(msg)  # append assistant message (may include tool_calls)

        if not msg.tool_calls:          # model produced final text
            return msg.content

        # Execute every tool call (parallel support)
        for tc in msg.tool_calls:
            args = json.loads(tc.function.arguments)
            result = dispatch_tool(tc.function.name, args)
            print(f'  [tool] {tc.function.name}({args}) → {result}')
            messages.append({
                'role': 'tool',
                'tool_call_id': tc.id,
                'content': result,
            })

    return 'Max rounds reached'


# ── Anthropic tool use ────────────────────────────────────────────────────────

ANTHROPIC_TOOLS = [
    {
        'name': 'get_weather',
        'description': 'Get current weather for a city',
        'input_schema': {
            'type': 'object',
            'properties': {
                'city': {'type': 'string'},
                'unit': {'type': 'string', 'enum': ['celsius', 'fahrenheit']},
            },
            'required': ['city'],
        },
    },
    {
        'name': 'calculate',
        'description': 'Evaluate a mathematical expression',
        'input_schema': {
            'type': 'object',
            'properties': {
                'expression': {'type': 'string'},
            },
            'required': ['expression'],
        },
    },
]


def anthropic_tool_loop(user_message: str, max_rounds: int = 5) -> str:
    """Anthropic tool-use agentic loop."""
    messages = [{'role': 'user', 'content': user_message}]

    for _round in range(max_rounds):
        response = anthropic_client.messages.create(
            model='claude-haiku-4-5-20251001',
            max_tokens=1024,
            tools=ANTHROPIC_TOOLS,
            messages=messages,
        )

        # Append assistant turn (all content blocks)
        messages.append({'role': 'assistant', 'content': response.content})

        if response.stop_reason == 'end_turn':   # no tool calls
            text_blocks = [b.text for b in response.content if hasattr(b, 'text')]
            return ' '.join(text_blocks)

        # stop_reason == 'tool_use' — execute tool_use blocks
        tool_results = []
        for block in response.content:
            if block.type == 'tool_use':
                result = dispatch_tool(block.name, block.input)  # input is already dict
                print(f'  [tool] {block.name}({block.input}) → {result}')
                tool_results.append({
                    'type': 'tool_result',
                    'tool_use_id': block.id,
                    'content': result,
                })

        messages.append({'role': 'user', 'content': tool_results})

    return 'Max rounds reached'


# ── Demo ──────────────────────────────────────────────────────────────────────

if __name__ == '__main__':
    queries = [
        'What is the weather in London and Tokyo?',
        'What products do we have in stock? Also calculate 29.99 * 150.',
    ]

    print('=== OpenAI Function Calling ===')
    for q in queries:
        print(f'Q: {q}')
        answer = openai_tool_loop(q)
        print(f'A: {answer}\n')

    print('\n=== Anthropic Tool Use ===')
    for q in queries[:1]:
        print(f'Q: {q}')
        answer = anthropic_tool_loop(q)
        print(f'A: {answer}\n')

