products = {'widget pro':{'price':29.99,'stock':150},'gadget plus':{'price':49.99,'stock':0}}

def get_product(name):
    p = products.get(name.lower())
    return p or {'error':'Not found'}

def check_availability(product_name, quantity):
    p = products.get(product_name.lower())
    if not p: return {'available':False,'reason':'Product not found'}
    if p['stock'] < quantity: return {'available':False,'reason':f'Only {p["stock"]} in stock'}
    return {'available':True,'reason':'In stock'}

def calculate_total(product_name, quantity):
    p = products.get(product_name.lower())
    if not p: return {'error':'Not found'}
    return {'total': p['price'] * quantity, 'unit_price': p['price']}
